  %umin = call i32 @llvm.smin.i32(i32 %smin, i32 20)
  ret i32 %umin
}

define i32 @test_smin_umin2(i32 %x) {
  %smin = call i32 @llvm.umin.i32(i32 %x, i32 20)
  %umin = call i32 @llvm.smin.i32(i32 %smin, i32 10)
